function Thermostat() {
  const [target, setTarget] = React.useState(72);
  const [mode, setMode] = React.useState('heat');
  const [current, setCurrent] = React.useState(68);

  React.useEffect(() => {
    const interval = setInterval(() => {
      setCurrent(c => Math.round((c + (Math.random() - 0.5)) * 10) / 10);
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  const modes = ['off', 'heat', 'cool', 'auto'];
  const modeColors = { off: '#6b7280', heat: '#ef4444', cool: '#3b82f6', auto: '#10b981' };

  return (
    <div style={{ fontFamily: 'system-ui', background: '#111827', color: '#f3f4f6', width: '100%', height: '100%', display: 'flex', flexDirection: 'column', padding: 16, borderRadius: 8, boxSizing: 'border-box' }}>
      <div style={{ fontSize: 14, fontWeight: 600, marginBottom: 12, color: '#9ca3af' }}>Living Room Thermostat</div>
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', flex: 1, flexDirection: 'column' }}>
        <div style={{ fontSize: 48, fontWeight: 700, color: modeColors[mode] }}>{Math.round(target)}°</div>
        <div style={{ fontSize: 14, color: '#9ca3af', marginTop: 4 }}>Current: {current.toFixed(1)}°F</div>
      </div>
      <input type="range" min="55" max="85" value={target} onChange={e => setTarget(Number(e.target.value))} style={{ width: '100%', accentColor: modeColors[mode], margin: '12px 0' }} />
      <div style={{ display: 'flex', gap: 8, justifyContent: 'center' }}>
        {modes.map(m => (
          <button key={m} onClick={() => setMode(m)} style={{ flex: 1, padding: '8px 0', borderRadius: 6, border: 'none', background: mode === m ? modeColors[m] : '#1f2937', color: '#fff', fontWeight: 600, fontSize: 12, cursor: 'pointer', textTransform: 'capitalize' }}>{m}</button>
        ))}
      </div>
    </div>
  );
}
render(<Thermostat/>);
